        __m512d dr=_mm512_sub_pd(x1_re,x2_re), di=_mm512_sub_pd(x1_im,x2_im);
        __m512d R1r=_mm512_fnmadd_pd(KHALF,ar,x0_re), R1i=_mm512_fnmadd_pd(KHALF,ai,x0_im);
        x0_re=_mm512_add_pd(x0_re,ar); x0_im=_mm512_add_pd(x0_im,ai);
        x2_re=_mm512_fmadd_pd(KS,di,R1r); x2_im=_mm512_fnmadd_pd(KS,dr,R1i);
        x1_re=_mm512_fnmadd_pd(KS,di,R1r); x1_im=_mm512_fmadd_pd(KS,dr,R1i);

        ST(&tbuf_re[0*8], x0_re);
        ST(&tbuf_im[0*8], x0_im);
        ST(&tbuf_re[1*8], x1_re);
        ST(&tbuf_im[1*8], x1_im);
        ST(&tbuf_re[2*8], x2_re);
        ST(&tbuf_im[2*8], x2_im);
        /* Bin 0: scalar scatter */
        out_re[(k+0)*ovs+os*0] = tbuf_re[0*8+0];
        out_re[(k+1)*ovs+os*0] = tbuf_re[0*8+1];
        out_re[(k+2)*ovs+os*0] = tbuf_re[0*8+2];
        out_re[(k+3)*ovs+os*0] = tbuf_re[0*8+3];
        out_re[(k+4)*ovs+os*0] = tbuf_re[0*8+4];
        out_re[(k+5)*ovs+os*0] = tbuf_re[0*8+5];
        out_re[(k+6)*ovs+os*0] = tbuf_re[0*8+6];
